class Solution:
    def shortestMatchingSubstring(self, s: str, p: str) -> int:
        def match(s, p, i, j):
            while j < len(p) and i < len(s):
                if p[j] == '*':
                    k = j + 1
                    while k < len(p) and p[k] == '*': k += 1
                    if k == len(p): return True
                    while i <= len(s):
                        if match(s, p, i, k): return True
                        i += 1
                    return False
                if p[j] != s[i]: return False
                i += 1
                j += 1
            return i == len(s) and j == len(p)

        first_star = p.find('*')
        second_star = p.find('*', first_star + 1)
        min_len = float('inf')
        for i in range(len(s)):
            for j in range(i, len(s)):
                substr = s[i:j+1]
                if match(substr, p, 0, 0):
                    min_len = min(min_len, j - i + 1)
        return min_len if min_len != float('inf') else -1
